**Recommendation:**
```javascript
// Only expose user emails to authenticated users
app.get('/users', (req, res) => {
  // Check authentication first
  if (!req.headers.authorization) {
    return res.status(401).json({ error: 'Unauthorized' });
  }

  res.json([
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ]);
});

// Public endpoint without sensitive data
app.get('/users/public', (req, res) => {
  res.json([
    { id: 1, name: 'Alice' },
    { id: 2, name: 'Bob' },
  ]);
});
```

---

### **5. No Error Handling / Information Disclosure (Medium Risk)**
**Issue:** No error handling middleware. Errors could expose stack traces and internal details.

**Vulnerability:** Stack traces visible in errors help attackers understand application structure.

**Recommendation:**
```javascript
const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');

const app = express();

app.use(helmet());
app.use(rateLimit({ windowMs: 15 * 60 * 1000, max: 100 }));

app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res) => {
  res.json([
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ]);
});

// 404 handler
app.use((req, res) => {
  res.status(404).json({ error: 'Not Found' });
});

// Error handling middleware (must be last)
app.use((err, req, res, next) => {
  console.error(err.stack);

  // Never expose error details to client in production
  const isDevelopment = process.env.NODE_ENV === 'development';

  res.status(err.status || 500).json({
    error: isDevelopment ? err.message : 'Internal Server Error',
    ...(isDevelopment && { stack: err.stack })
  });
});

app.listen(3000, () => {
  console.log('Server running on port 3000');
});

module.exports = app;
```

---

### **6. Missing CORS Configuration (Medium Risk)**
**Issue:** No CORS (Cross-Origin Resource Sharing) policy defined.

**Vulnerability:** Could allow unauthorized cross-origin requests or be too permissive.

**Recommendation:**
```javascript
const cors = require('cors');
const express = require('express');

const app = express();

// Restrictive CORS configuration
const corsOptions = {
  origin: process.env.ALLOWED_ORIGINS?.split(',') || ['http://localhost:3000'],
  credentials: true,
  methods: ['GET', 'POST'],
  allowedHeaders: ['Content-Type', 'Authorization'],
  maxAge: 86400 // 24 hours
};

app.use(cors(corsOptions));

app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.listen(3000, () => {
  console.log('Server running on port 3000');
});

module.exports = app;
```

---

### **7. No Dependency Vulnerability Scanning (Medium Risk)**
**Issue:** No lock file or security scanning mentioned.

**Recommendation:**
```bash
# Install security audit tools
npm audit
npm install --save-dev snyk

# Add to package.json scripts
{
  "scripts": {
    "test": "jest",
    "audit": "npm audit && snyk test",
    "audit:fix": "npm audit fix && snyk fix"
  }
}
```

